import{_ as l,H as t,f as a,i as e}from"./chunks/framework.eFU6Tutu.js";const r="/assets/ratatouille.BOulku2Y.jpg",o="/assets/chicken_roast.CIEudmXO.jpg",m=JSON.parse('{"title":"Рецепты из перца","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/peppers.md","filePath":"recipes/peppers.md"}'),d={name:"recipes/peppers.md"};function h(s,i,n,p,c,u){return t(),a("div",null,[...i[0]||(i[0]=[e('<h1 id="рецепты-из-перца" tabindex="-1">Рецепты из перца <a class="header-anchor" href="#рецепты-из-перца" aria-label="Permalink to &quot;Рецепты из перца&quot;">​</a></h1><h2 id="рататуи" tabindex="-1">Рататуй <a class="header-anchor" href="#рататуи" aria-label="Permalink to &quot;Рататуй&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-4-порции" tabindex="-1">Ингредиенты (на 4 порции) <a class="header-anchor" href="#ингредиенты-на-4-порции" aria-label="Permalink to &quot;Ингредиенты (на 4 порции)&quot;">​</a></h3><ul><li>Баклажаны — 600 г (2 шт.)</li><li>Кабачки — 600 г (2 шт.)</li><li>Помидоры — 1 кг (7 шт.)</li><li>Лук репчатый — 150 г (2 шт.)</li><li>Перец болгарский — 400 г (4 шт.)</li><li>Чеснок — 4 зубчика</li><li>Оливковое масло — 100 мл</li><li>Паприка молотая — 1 ч. ложка</li><li>Прованские травы — по вкусу</li><li>Зелень петрушки — для подачи</li><li>Соль — по вкусу</li></ul></div><div><p><img src="'+r+'" alt="Рататуй"></p></div></div><h3 id="пищевая-ценность-на-1-порцию" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>4 г</td><td>12 г</td><td>25 г</td><td>220</td></tr></tbody></table><h3 id="приготовление" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 1 ч 20 мин</p><ol><li>Лук мелко нарежьте и обжарьте на 2 ст. ложках оливкового масла до прозрачности, посолите.</li><li>С 3 помидоров снимите кожицу (обдайте кипятком), нарежьте кубиками.</li><li>У болгарского перца удалите плодоножки и семена, нарежьте кубиками.</li><li>Добавьте помидоры и перец к луку, обжаривайте 10 минут.</li><li>Измельчите обжаренные овощи блендером до состояния соуса.</li><li>Готовый соус ровным слоем выложите на дно формы для запекания.</li><li>Разогрейте духовку до 180°С.</li><li>Кабачки, баклажаны и оставшиеся помидоры нарежьте кружочками толщиной 5 мм.</li><li>Выложите овощи сверху на соус, чередуя (кабачок — баклажан — помидор). Посолите.</li><li>Смешайте оливковое масло с измельчённым чесноком, паприкой и прованскими травами. Смажьте овощи сверху.</li><li>Накройте форму фольгой, запекайте 30 минут.</li><li>Снимите фольгу, запекайте ещё 20 минут до румяной корочки.</li><li>Готовый рататуй посыпьте мелко нарезанной свежей зеленью.</li></ol><blockquote><p><strong>Совет:</strong> Овощи лучше укладывать в шахматном порядке, при необходимости разрезая их пополам — так блюдо выглядит красивее и пропитывается равномернее.</p></blockquote><h2 id="жаркое-из-курицы-с-картошкои" tabindex="-1">Жаркое из курицы с картошкой <a class="header-anchor" href="#жаркое-из-курицы-с-картошкои" aria-label="Permalink to &quot;Жаркое из курицы с картошкой&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;"><div><h3 id="ингредиенты-на-3-порции" tabindex="-1">Ингредиенты (на 3 порции) <a class="header-anchor" href="#ингредиенты-на-3-порции" aria-label="Permalink to &quot;Ингредиенты (на 3 порции)&quot;">​</a></h3><ul><li>Куриное бедро (филе без костей и кожи) — 500 г (3 шт.)</li><li>Картофель — 600 г</li><li>Перец болгарский красный — 200 г</li><li>Помидор — 100 г</li><li>Лук репчатый — 130 г</li><li>Чеснок — 3-4 зубчика</li><li>Петрушка свежая — 20 г</li><li>Укроп свежий — 10 г</li><li>Паприка молотая — 1 ч. ложка</li><li>Соль, чёрный перец — по вкусу</li><li>Масло растительное — 75 мл (5 ст. ложек)</li></ul></div><div><p><img src="'+o+'" alt="Жаркое из курицы с картошкой"></p></div></div><h3 id="пищевая-ценность-на-1-порцию-1" tabindex="-1">Пищевая ценность (на 1 порцию) <a class="header-anchor" href="#пищевая-ценность-на-1-порцию-1" aria-label="Permalink to &quot;Пищевая ценность (на 1 порцию)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>35 г</td><td>28 г</td><td>42 г</td><td>540</td></tr></tbody></table><h3 id="приготовление-1" tabindex="-1">Приготовление <a class="header-anchor" href="#приготовление-1" aria-label="Permalink to &quot;Приготовление&quot;">​</a></h3><p>Общее время приготовления: 1 час</p><ol><li>Куриное филе нарежьте кубиками, посолите, поперчите, посыпьте паприкой.</li><li>Картофель очистите и нарежьте крупными дольками.</li><li>Лук нарежьте полукольцами, перец — соломкой, помидор — кубиками.</li><li>В глубокой сковороде или казане разогрейте масло.</li><li>Обжарьте курицу до золотистой корочки (5-7 минут), переложите в отдельную тарелку.</li><li>В этом же масле обжарьте картофель до румяной корочки (10-12 минут).</li><li>Добавьте лук, обжаривайте 3-4 минуты.</li><li>Верните курицу в сковороду, добавьте перец и помидоры.</li><li>Убавьте огонь, накройте крышкой и тушите 15-20 минут до готовности.</li><li>В конце добавьте измельчённый чеснок и зелень, перемешайте.</li></ol><blockquote><p><strong>Совет:</strong> Для более насыщенного вкуса можно добавить 100 мл куриного бульона или воды при тушении.</p></blockquote><h3 id="другие-рецепты" tabindex="-1">Другие рецепты <a class="header-anchor" href="#другие-рецепты" aria-label="Permalink to &quot;Другие рецепты&quot;">​</a></h3><ul><li><a href="/recipes/tomatoes.html">Рецепты с помидорами</a></li><li><a href="/recipes/mint.html">Мята</a></li><li><a href="/recipes/basil.html">Базилик</a></li></ul>',19)])])}const f=l(d,[["render",h]]);export{m as __pageData,f as default};
